const less = require('./packages/less');

// Test case to reproduce the @media print bug
async function testPrintBug() {
    try {
        const lessCode = `@media print(max-width: 992px) {
  .main-view {
    display: flex;
    flex-direction: row;
  }
}`;

        const result = await less.render(lessCode);
        console.log('✅ Test passed - CSS generated successfully:');
        console.log(result.css);
        return true;
    } catch (error) {
        console.log('❌ Test failed - Error encountered:');
        console.log(error.message);
        console.log('Stack:', error.stack);
        return false;
    }
}

// Test normal @media query for comparison
async function testNormalMedia() {
    try {
        const lessCode = `@media (max-width: 992px) {
  .main-view {
    display: flex;
    flex-direction: row;
  }
}`;

        const result = await less.render(lessCode);
        console.log('✅ Normal @media test passed:');
        console.log(result.css);
        return true;
    } catch (error) {
        console.log('❌ Normal @media test failed:');
        console.log(error.message);
        return false;
    }
}

