const less = require('./packages/less');

// Debug script to understand the evalFunction behavior
async function debugEvalFunction() {
    console.log('Debugging evalFunction behavior...\n');

    // Test case from the bug report: @media print(max-width: 992px)
    const bugCase = `@media print(max-width: 992px) {
  .main-view { display: flex; }
}`;

    console.log('=== Testing bug case ===');
    console.log('Input LESS:', bugCase);

    try {
        const result = await less.render(bugCase, { dumpLineNumbers: 'comments' });
        console.log('\n✅ Generated CSS:');
        console.log(result.css);
        console.log('\nNote: The issue is likely in the CSS minification stage with lightningcss');
        console.log('The generated CSS is syntactically correct but may not be valid CSS3');
        console.log('@media print(max-width: 992px) should be @media print and (max-width: 992px)');
    } catch (error) {
        console.log('\n❌ Error:', error.message);
    }

    // Test correct syntax for comparison
    console.log('\n=== Testing correct syntax ===');
    const correctCase = `@media print and (max-width: 992px) {
  .main-view { display: flex; }
}`;

    console.log('Input LESS:', correctCase);

    try {
        const result = await less.render(correctCase);
        console.log('\n✅ Generated CSS:');
        console.log(result.css);
    } catch (error) {
        console.log('\n❌ Error:', error.message);
    }
}

debugEvalFunction().catch(console.error);

