const less = require('./packages/less');

// Comprehensive test to understand exactly what syntax LESS supports
async function testComprehensiveSyntax() {
    console.log('=== Comprehensive @media Syntax Tests ===\n');

    const testCases = [
        // Standard CSS syntax - should work
        {
            name: 'Standard CSS: @media print',
            code: `@media print { .test { color: red; } }`,
            expected: true
        },
        {
            name: 'Standard CSS: @media print and (max-width: 992px)',
            code: `@media print and (max-width: 992px) { .test { color: red; } }`,
            expected: true
        },

        // Bug case - LESS allows this but it may generate invalid CSS
        {
            name: 'Bug case: @media print(max-width: 992px)',
            code: `@media print(max-width: 992px) { .test { color: red; } }`,
            expected: true
        },

        // Other media types with features
        {
            name: 'Media type with features: @media screen(max-width: 992px)',
            code: `@media screen(max-width: 992px) { .test { color: red; } }`,
            expected: true
        },

        // Complex nested cases
        {
            name: 'Nested media query',
            code: `
                .container {
                    @media print(max-width: 992px) {
                        width: 100%;
                    }
                }
            `,
            expected: true
        },

        // Media query with variables
        {
            name: 'Media query with variable',
            code: `
                @breakpoint: 992px;
                @media print(max-width: @breakpoint) { .test { color: red; } }
            `,
            expected: true
        },

        // Empty media features
        {
            name: 'Empty media features: @media print()',
            code: `@media print() { .test { color: red; } }`,
            expected: false // This is invalid syntax
        }
    ];

    for (const testCase of testCases) {
        console.log(`Testing: ${testCase.name}`);
        console.log(`Input: ${testCase.code.substring(0, 50)}${testCase.code.length > 50 ? '...' : ''}`);

