const less = require('./packages/less');

// Debug script to understand the media query structure
async function debugMediaStructure() {
    console.log('Debugging media query structure...\n');

    const lessCode = `@media print(max-width: 992px) {
  .main-view { display: flex; }
}`;

    console.log('Input LESS:');
    console.log(lessCode);
    console.log('');

    try {
        // Parse without evaluating to see the AST structure
        const result = await less.render(lessCode, {
            dumpLineNumbers: 'comments',
            compress: false
        });

        console.log('✅ Generated CSS:');
        console.log(result.css);

        // Now let's check what happens if we look at the parse tree
        console.log('\n=== Analyzing the AST structure ===');

        // Create a custom plugin to inspect the AST
        const inspectPlugin = {
            install: function(less, pluginManager) {
                const visitor = new less.visitors.Visitor({
                    visitMedia: function(mediaNode) {
                        console.log('Media node found:');
                        console.log('- Type:', mediaNode.type);
                        console.log('- Features type:', mediaNode.features && mediaNode.features.type);
                        console.log('- Features value:', mediaNode.features && mediaNode.features.value);

                        if (mediaNode.features && mediaNode.features.value && Array.isArray(mediaNode.features.value)) {
                            console.log('- Features value details:');
                            mediaNode.features.value.forEach((item, index) => {
                                console.log(`  [${index}] Type: ${item.type}, Value: ${item.value || 'N/A'}`);
                                if (item.value && Array.isArray(item.value)) {
                                    item.value.forEach((sub, subIndex) => {
                                        console.log(`    [${index}.${subIndex}] Type: ${sub.type}, Content: ${sub.value || JSON.stringify(sub)}`);
                                    });
                                }
                            });
                        }

                        return mediaNode;
                    }
                });

                pluginManager.addVisitor(visitor);
            }
        };

        console.log('\n=== Testing with AST inspection plugin ===');
        const resultWithPlugin = await less.render(lessCode, { plugins: [inspectPlugin] });

    } catch (error) {
        console.log('❌ Error:', error.message);
    }
}

debugMediaStructure().catch(console.error);

