                                    if (item.value && Array.isArray(item.value)) {
                                        item.value.forEach((subItem, subIndex) => {
                                            console.log(`      Sub [${subIndex}]:`);
                                            console.log('        - Type:', subItem.type);
                                            console.log('        - Value:', subItem.value || '(no value)');

                                            if (subItem.noSpacing !== undefined) {
                                                console.log('        - noSpacing:', subItem.noSpacing);
                                            }
                                        });
                                    }
                                });
                            }
                        }

                        return mediaNode;
                    }
                });

                pluginManager.addVisitor(visitor);
            }
        };

        const resultWithInspection = await less.render(lessCode, {
            plugins: [inspector]
        });

        console.log('\nFinal CSS after inspection:');
        console.log(resultWithInspection.css);

    } catch (error) {
        console.log('❌ Error:', error.message);
        console.log(error.stack);
    }
}

