// Test to understand the noSpacing behavior
async function testNoSpacingIssue() {
    console.log('=== Testing noSpacing Property Behavior ===\n');

    // Different test cases to understand when noSpacing is set
    const testCases = [
        {
            name: 'Media type with parens but spacing',
            code: `@media print (max-width: 992px) { .test { color: red; } }`,
            description: 'Space between print and ('
        },
        {
            name: 'Media type with parens no spacing',
            code: `@media print(max-width: 992px) { .test { color: red; } }`,
            description: 'No space between print and ( - our bug case'
        },
        {
            name: 'Media type with proper syntax',
            code: `@media print and (max-width: 992px) { .test { color: red; } }`,
            description: 'Correct syntax with "and"'
        }
    ];

    for (const testCase of testCases) {
        console.log(`\n--- ${testCase.name} ---`);
        console.log(`Description: ${testCase.description}`);
        console.log(`Input: ${testCase.code}`);

        try {
            const result = await less.render(testCase.code);
            console.log('✅ Generated CSS:');
            console.log(result.css);

            // The key insight: regardless of input spacing, we always want:
            // @media print and (max-width: 992px)
            // Instead of:
            // @media print(max-width: 992px)

        } catch (error) {
            console.log('❌ Error:', error.message);
        }
    }

    console.log('\n=== Analysis ===');
    console.log('The issue is that LESS generates @media print(max-width: 992px)');
    console.log('which is not valid CSS3 syntax. It should generate @media print and (max-width: 992px)');
    console.log('');
    console.log('The fix should ensure that when a media type is directly followed by');
    console.log('parentheses (indicating media features), the "and" keyword is inserted.');
}

testNoSpacingIssue().catch(console.error);

